DROP SECRET IF EXISTS kafka_password CASCADE;

CREATE SECRET kafka_password AS 'eyJhbGciOiJIUzI1NiIsImtpZCI6IlhaYXZsWHkrajczYUxwYlEiLCJ0eXAiOiJKV1QifQ..9Bf0sxsubD4RBiP9usGt4FzlasDrJO9QtHXFBZr3960';

CREATE CONNECTION kafka_connection TO KAFKA (
    BROKER 'localhost',
    SECURITY PROTOCOL = 'SASL_PLAINTEXT',
    SASL MECHANISMS = 'PLAIN',
    SASL USERNAME = 'dev-user',
    SASL PASSWORD = SECRET kafka_password
);

CREATE SOURCE my_source
  FROM KAFKA CONNECTION kafka_connection (TOPIC 'demo/wikipedia/recentchange-sampled')
  FORMAT JSON;

